    dense_data[key] = value

    # Extract updated sparse data
    data_flat = dense_data.reshape(-1, self.shape[3], order='F')
    self.data = data_flat[self._lookup, :].T

def _to_dense_array(self) -> np.ndarray:
    """Convert sparse data to dense 4D array."""
    dense = np.zeros(self.shape, dtype=self.data.dtype, order='F')
    data_flat = dense.reshape(-1, self.shape[3], order='F')
    data_flat[self._lookup, :] = self.data.T
    return dense

def series(self, x, y=None, z=None) -> np.ndarray:
    """Extract time series for voxel(s)."""
    if y is not None and z is not None:
        # Single voxel
        linear_idx = np.ravel_multi_index((x, y, z), self.shape[:3], order='F')
        sparse_idx = self._inverse_lookup[linear_idx]
        if sparse_idx == -1:
            return np.zeros(self.shape[3])
        return self.data[:, sparse_idx]
    elif isinstance(x, np.ndarray):
        if x.ndim == 2 and x.shape[1] == 3:
            # Nx3 matrix of coordinates
            result = np.zeros((self.shape[3], x.shape[0]))
            for i, coord in enumerate(x):
                linear_idx = np.ravel_multi_index(coord, self.shape[:3], order='F')
                sparse_idx = self._inverse_lookup[linear_idx]
                if sparse_idx != -1:
                    result[:, i] = self.data[:, sparse_idx]
            return result
        elif x.ndim == 1:
            # Linear indices
            result = np.zeros((self.shape[3], len(x)))
            for i, idx in enumerate(x):
                sparse_idx = self._inverse_lookup[idx]
                if sparse_idx != -1:
                    result[:, i] = self.data[:, sparse_idx]
            return result
    elif isinstance(x, int):
        # Single linear index
        sparse_idx = self._inverse_lookup[x]
        if sparse_idx == -1:
            return np.zeros(self.shape[3])
        return self.data[:, sparse_idx]
    else:
        raise ValueError("Invalid input for series extraction")

def as_sparse(self, mask=None) -> 'SparseNeuroVec':
    """Already sparse, return self or apply new mask."""
    if mask is None:
        return self
    else:
        # Apply additional mask
        raise NotImplementedError("Additional masking not yet implemented")

def as_dense(self) -> DenseNeuroVec:
    """Convert to dense representation."""
    dense_data = self._to_dense_array()
    return DenseNeuroVec(dense_data, self.space, self.label)

def sub_vector(self, indices: Union[int, slice, np.ndarray]) -> 'SparseNeuroVec':
    """Extract subset of volumes."""
    if isinstance(indices, int):
        indices = [indices]
    elif isinstance(indices, slice):
        indices = list(range(*indices.indices(self.shape[3])))

    sub_data = self.data[indices, :]

    sub_space = NeuroSpace((*self.shape[:3], len(indices)),
                         spacing=self.spacing,
                         origin=self.origin,
                         axes=self.space.axes)

    return SparseNeuroVec(sub_data, sub_space, self.mask, self.label)

def concat(self, *others: 'SparseNeuroVec') -> 'SparseNeuroVec':
    """Concatenate multiple SparseNeuroVecs along time dimension."""
    all_vecs = [self] + list(others)

    # Check compatibility
    for vec in all_vecs[1:]:
        if not np.array_equal(vec.mask.data, self.mask.data):
            raise ValueError("All SparseNeuroVecs must have same mask")

    # Concatenate data
    all_data = [vec.data for vec in all_vecs]
    concat_data = np.vstack(all_data)

    # Create new space
    concat_space = NeuroSpace((*self.shape[:3], concat_data.shape[0]),
                            spacing=self.spacing,
                            origin=self.origin,
                            axes=self.space.axes)

    return SparseNeuroVec(concat_data, concat_space, self.mask, self.label)

    def _arithmetic_op(self, other, op):
        """Perform arithmetic operation."""
        if isinstance(other, (int, float)):
            # Scalar operation
            result_data = op(self.data, other)
            return SparseNeuroVec(result_data, self.space, self.mask, self.label)
        elif isinstance(other, SparseNeuroVec):
            # Sparse-sparse operation
            if not np.array_equal(other.mask.data, self.mask.data):
                raise ValueError("SparseNeuroVecs must have same mask for arithmetic")
            result_data = op(self.data, other.data)
            return SparseNeuroVec(result_data, self.space, self.mask, self.label)
        elif isinstance(other, DenseNeuroVec):
            # Convert to dense for operation
            return self.as_dense()._arithmetic_op(other, op)
        elif isinstance(other, NeuroVol):
            # Vector-volume operation
            if other.shape != self.shape[:3]:
                raise ValueError("NeuroVol must match spatial dimensions of NeuroVec")
            # Extract volume values at mask locations
            vol_masked = other.values()[self._lookup]
            # Broadcast across time
            result_data = op(self.data, vol_masked[np.newaxis, :])
            return SparseNeuroVec(result_data, self.space, self.mask, self.label)
        else:
            return NotImplemented


def neurovecseq(vecs: List[Union[DenseNeuroVec, NeuroVol]], label: str = "") -> DenseNeuroVec:
    """Create NeuroVec from sequence of volumes or vectors.

    Parameters
    ----------
    vecs : list
        List of NeuroVol objects or DenseNeuroVec objects
    label : str, optional
        Label for the result

    Returns
    -------
    DenseNeuroVec
        Combined 4D vector

    R Equivalent
    ------------
    neuroim2::NeuroVecSeq
    """
    if not vecs:
        raise ValueError("Empty vector list")


def __getitem__(self, key):
    """Extract values using various indexing methods."""
    if isinstance(key, tuple) and len(key) == 3:
        # Convert 3D to linear index
        idx = self.space.grid_to_index(np.array([key]))[0]
        return self.sparse_data[0, idx]
    elif isinstance(key, np.ndarray):
        if key.ndim == 2 and key.shape[1] == 3:
            # Nx3 matrix of coordinates
            indices = self.space.grid_to_index(key)
            return self.sparse_data[0, indices].A.ravel()
        elif key.ndim == 1:
            # Linear indices
            return self.sparse_data[0, key].A.ravel()
    elif isinstance(key, (int, slice)):
        return self.sparse_data[0, key]
    else:
        # Convert to dense for complex indexing
        return self.as_dense()[key]

def __setitem__(self, key, value):
    """Set values using various indexing methods."""
    # Note: Setting values in sparse array can be inefficient
    if isinstance(key, tuple) and len(key) == 3:
        idx = self.space.grid_to_index(np.array([key]))[0]
        self.sparse_data[0, idx] = value
    elif isinstance(key, int):
        self.sparse_data[0, key] = value
    else:
        raise NotImplementedError("Complex indexing for setting not yet implemented for SparseNeuroVol")

def values(self) -> np.ndarray:
    """Get all values (including zeros)."""
    return self.sparse_data.toarray().ravel()

def as_dense(self) -> DenseNeuroVol:
    """Convert to dense representation."""
    dense_data = self.sparse_data.toarray().reshape(self.shape, order='F')
    return DenseNeuroVol(dense_data, self.space, self.label)

def as_sparse(self, mask=None) -> 'SparseNeuroVol':
    """Already sparse, optionally apply new mask."""
    if mask is None:
        return self
    else:
        # Apply additional mask
        dense = self.as_dense()
        return dense.as_sparse(mask)

def as_logical(self) -> 'LogicalNeuroVol':
    """Convert to logical representation."""
    return self.as_dense().as_logical()

def as_array(self) -> np.ndarray:
    """Convert to numpy array."""
    return self.as_dense().data

def as_numeric(self) -> np.ndarray:
    """Get non-zero values only.

    R Equivalent
    ------------
    neuroim2::as.numeric
    """
    return self.data

@property
def nnz(self) -> int:
    """Number of non-zero elements."""
    return self.sparse_data.nnz

def _arithmetic_op(self, other, op):
    """Perform arithmetic operation."""
    if isinstance(other, (int, float)):
        # Scalar operation preserves sparsity
        new_data = op(self.data, other)
        return SparseNeuroVol(new_data, self.space, self.indices, self.label)
    elif isinstance(other, SparseNeuroVol):
        # For sparse-sparse operations, we need to handle index union
        # Convert both to dense for now
        dense1 = self.as_dense()
        dense2 = other.as_dense()
        result = dense1._arithmetic_op(dense2, op)
        return result
    else:
        # Convert to dense for operations with dense volumes
        dense = self.as_dense()
        result = dense._arithmetic_op(other, op)
        return result

def _comparison_op(self, value, op):
    """Perform comparison operation."""
    if isinstance(value, (int, float)):
        # Create logical volume
        dense = self.as_dense()
        return dense._comparison_op(value, op)
    else:
        dense = self.as_dense()
        return dense._comparison_op(value, op)

        yield self.m

def axis_set(ndim: int, axes: List[str] = None) -> Union[AxisSet1D, AxisSet2D, AxisSet3D, AxisSet4D, AxisSet5D]:
    if axes is None:
        axes = ["x", "y", "z", "t", "v"][:ndim]

    if len(axes) != ndim:
        raise ValueError(f"Number of axes ({len(axes)}) must match ndim ({ndim})")

    named_axes = [NamedAxis(ax, 1) for ax in axes]

    if ndim == 1:
        return AxisSet1D(named_axes[0])
    elif ndim == 2:
        return AxisSet2D(named_axes[0], named_axes[1])
    elif ndim == 3:
        return AxisSet3D(named_axes[0], named_axes[1], named_axes[2])
    elif ndim == 4:
        return AxisSet4D(named_axes[0], named_axes[1], named_axes[2], named_axes[3])
    elif ndim == 5:
        return AxisSet5D(named_axes[0], named_axes[1], named_axes[2], named_axes[3], named_axes[4])
    else:
        raise ValueError("ndim must be between 1 and 5")

def axis_names(x: Union[AxisSet1D, AxisSet2D, AxisSet3D, AxisSet4D, AxisSet5D]) -> List[str]:
    return [getattr(x, attr).axis for attr in "ijklm"[:x.ndim]]

def axis_directions(x: Union[AxisSet1D, AxisSet2D, AxisSet3D, AxisSet4D, AxisSet5D]) -> List[int]:
    return [getattr(x, attr).direction for attr in "ijklm"[:x.ndim]]

